public int[] fix45(int[] nums) {
    for (int i = 0; i < nums.length - 1; i++) {
        if (nums[i] == 4) {
            // If the next element is not a 5, we need to find a 5 and swap it
            if (nums[i + 1] != 5) {
                // Find a 5 in the array
                for (int j = i + 2; j < nums.length; j++) {
                    if (nums[j] == 5) {
                        // Swap nums[i + 1] and nums[j]
                        int temp = nums[i + 1];
                        nums[i + 1] = nums[j];
                        nums[j] = temp;
                        break;
                    }
                }
            }
        }
    }
    return nums;
}

